import React, { useState, useRef, useEffect } from 'react';

function DrawingCanvas({ cameraData, onSave }) {
  // Kiểm tra cameraData
  if (!cameraData) {
    return (
      <div style={{ padding: '40px', textAlign: 'center' }}>
        <p>Không có dữ liệu camera. Vui lòng thử lại.</p>
      </div>
    );
  }

  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [drawing, setDrawing] = useState(false);
  const [zones, setZones] = useState([]);
  const [currentZone, setCurrentZone] = useState({
    name: '',
    type: 1, // Mặc định UNKNOWN_PERSON
    lines: [],
    polyPoints: []
  });
  const [ix, setIx] = useState(-1);
  const [iy, setIy] = useState(-1);
  const [selectedZoneIndex, setSelectedZoneIndex] = useState(null);
  const [zoneName, setZoneName] = useState('');
  const [zoneType, setZoneType] = useState(1);

  const canvasRef = useRef(null);
  const imageRef = useRef(null);

  const FIXED_WIDTH = 800;
  const FIXED_HEIGHT = 450;

  // Zone types
  const zoneTypes = [
    { value: 1, label: 'UNKNOWN_PERSON', color: '#ff6b6b' },
    { value: 2, label: 'NO_UNIFORM', color: '#4ecdc4' },
    { value: 3, label: 'ENTRY', color: '#45b7d1' }
  ];

  // Khởi tạo canvas
  useEffect(() => {
    if (canvasRef.current) {
      canvasRef.current.width = FIXED_WIDTH;
      canvasRef.current.height = FIXED_HEIGHT;
    }
  }, []);

  // Vẽ ảnh lên canvas
  useEffect(() => {
    if (canvasRef.current && cameraData.imagePreview) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');

      const img = new Image();
      img.src = cameraData.imagePreview;
      img.onload = () => {
        ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);
        redrawAll();
      };
    }
  }, [cameraData.imagePreview]);

  // Format output cho nhiều zones theo cấu trúc yêu cầu
  const generateOutput = () => {
    if (zones.length > 0) {
      const formattedZones = zones.map(zone => {
        // Format axis và coord theo đúng cấu trúc
        const axis = zone.lines[0] ? [
          Number((zone.lines[0][0] / FIXED_WIDTH).toFixed(3)),
          Number((zone.lines[0][1] / FIXED_HEIGHT).toFixed(3)),
          Number((zone.lines[0][2] / FIXED_WIDTH).toFixed(3)),
          Number((zone.lines[0][3] / FIXED_HEIGHT).toFixed(3))
        ] : [];

        // Nếu là ENTRY (type 3), coord là 8 điểm
        // Nếu không, coord là 4 điểm
        let coord = [];
        if (zone.type === 3) {
          // ENTRY: 8 điểm (4 điểm * 2 tọa độ)
          coord = zone.polyPoints.length >= 4 ? 
            zone.polyPoints.slice(0, 4).flatMap(p => [
              Number((p.x / FIXED_WIDTH).toFixed(3)),
              Number((p.y / FIXED_HEIGHT).toFixed(3))
            ]) : [];
        } else {
          // UNKNOWN_PERSON hoặc NO_UNIFORM: 4 điểm (2 điểm * 2 tọa độ)
          coord = zone.lines[1] ? [
            Number((zone.lines[1][0] / FIXED_WIDTH).toFixed(3)),
            Number((zone.lines[1][1] / FIXED_HEIGHT).toFixed(3)),
            Number((zone.lines[1][2] / FIXED_WIDTH).toFixed(3)),
            Number((zone.lines[1][3] / FIXED_HEIGHT).toFixed(3))
          ] : [];
        }

        return {
          ID: generateUUID(),
          type: zone.type,
          axis: axis,
          coord: coord
        };
      });

      return {
        list_camera: [
          {
            cam_info: {
              url: cameraData.rtspUrl || "",
              cam_id: generateUUID()
            },
            config: {
              direction: [],
              heatmap: {},
              layout: {},
              zone: formattedZones,
              reid: {
                faiss_switch: 0.6,
                faiss_staff_db: 0.8
              }
            }
          }
        ]
      };
    }

    return {
      list_camera: [
        {
          cam_info: {
            url: cameraData.rtspUrl || "",
            cam_id: generateUUID()
          },
          config: {
            direction: [],
            heatmap: {},
            layout: {},
            zone: [],
            reid: {
              faiss_switch: 0.6,
              faiss_staff_db: 0.8
            }
          }
        }
      ]
    };
  };

  const generateUUID = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  // Xử lý mouse down
  const handleMouseDown = (e) => {
    e.preventDefault();
    if (!canvasRef.current) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    if (currentStep === 3) {
      if (currentZone.polyPoints.length < 4) {
        setCurrentZone({
          ...currentZone,
          polyPoints: [...currentZone.polyPoints, { x, y }]
        });
      }
    } else {
      setDrawing(true);
      setIx(x);
      setIy(y);
    }
  };

  const handleMouseMove = (e) => {
    e.preventDefault();
    if (!drawing || !canvasRef.current || currentStep === 3) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    const ctx = canvasRef.current.getContext('2d');
    redrawAll();

    ctx.beginPath();
    ctx.moveTo(ix, iy);
    ctx.lineTo(x, y);

    if (currentStep === 1) {
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.setLineDash([5, 5]);
      ctx.stroke();
      ctx.setLineDash([]);
    } else if (currentStep === 2) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 2, true);
    }
  };

  const handleMouseUp = (e) => {
    e.preventDefault();
    if (!drawing || !canvasRef.current || currentStep === 3) return;

    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    if (x < 0 || x > FIXED_WIDTH || y < 0 || y > FIXED_HEIGHT) return;

    const newLine = [ix, iy, x, y];
    setCurrentZone({
      ...currentZone,
      lines: [...currentZone.lines, newLine]
    });
    setDrawing(false);

    if (currentStep === 1) {
      setCurrentStep(2);
    } else if (currentStep === 2) {
      setCurrentStep(3);
    }
  };

  // Hoàn thành zone hiện tại
  const handleCompleteZone = () => {
    if (!zoneName.trim()) {
      alert('Vui lòng nhập tên cho zone!');
      return;
    }

    if (currentZone.lines.length < 2) {
      alert('Chưa vẽ đủ Axis và Coord cho zone này!');
      return;
    }

    if (currentZone.polyPoints.length < 4) {
      alert('Chưa vẽ đủ 4 điểm Polygon cho zone này!');
      return;
    }

    // Tạo zone mới
    const newZone = {
      name: zoneName,
      type: zoneType,
      lines: currentZone.lines,
      polyPoints: currentZone.polyPoints
    };

    setZones([...zones, newZone]);
    setCurrentZone({
      name: '',
      type: 1,
      lines: [],
      polyPoints: []
    });
    setZoneName('');
    setZoneType(1);
    setCurrentStep(1);
    setSelectedZoneIndex(zones.length);
  };

  // Chọn zone để xem
  const handleSelectZone = (index) => {
    setSelectedZoneIndex(index);
    redrawAll();
  };

  // Xóa zone
  const handleDeleteZone = (index) => {
    const newZones = zones.filter((_, i) => i !== index);
    setZones(newZones);
    if (selectedZoneIndex === index) {
      setSelectedZoneIndex(null);
    }
    redrawAll();
  };

  // Cập nhật type cho zone
  const handleUpdateZoneType = (index, newType) => {
    const updatedZones = zones.map((zone, i) => 
      i === index ? { ...zone, type: newType } : zone
    );
    setZones(updatedZones);
  };

  // Hàm vẽ
  const drawPoint = (ctx, x, y, number, color = '#ff4444') => {
    ctx.beginPath();
    ctx.arc(x, y, 6, 0, 2 * Math.PI);
    ctx.fillStyle = color;
    ctx.fill();
    ctx.strokeStyle = 'white';
    ctx.lineWidth = 2;
    ctx.stroke();

    ctx.fillStyle = 'white';
    ctx.font = 'bold 14px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(number, x, y);
  };

  const drawLine = (ctx, x1, y1, x2, y2, color, width = 2) => {
    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.stroke();
  };

  const drawArrow = (ctx, fromX, fromY, toX, toY, color, width, isPreview = false) => {
    const headLength = isPreview ? 15 : 20;
    const angle = Math.atan2(toY - fromY, toX - fromX);

    ctx.beginPath();
    ctx.moveTo(fromX, fromY);
    ctx.lineTo(toX, toY);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    if (isPreview) ctx.setLineDash([5, 5]);
    ctx.stroke();
    if (isPreview) ctx.setLineDash([]);

    ctx.beginPath();
    ctx.moveTo(toX, toY);
    ctx.lineTo(
      toX - headLength * Math.cos(angle - Math.PI / 6),
      toY - headLength * Math.sin(angle - Math.PI / 6)
    );
    ctx.lineTo(
      toX - headLength * Math.cos(angle + Math.PI / 6),
      toY - headLength * Math.sin(angle + Math.PI / 6)
    );
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
  };

  // Vẽ zone cụ thể
  const drawZone = (ctx, zone, isSelected = false) => {
    const zoneTypeColor = zoneTypes.find(t => t.value === zone.type)?.color || '#00ff00';
    const color = isSelected ? '#ff0000' : zoneTypeColor;

    if (zone.lines[0]) {
      const [x1, y1, x2, y2] = zone.lines[0];
      drawLine(ctx, x1, y1, x2, y2, isSelected ? '#ff0000' : '#000000', isSelected ? 4 : 3);
    }

    if (zone.lines[1]) {
      const [x1, y1, x2, y2] = zone.lines[1];
      drawArrow(ctx, x1, y1, x2, y2, isSelected ? '#ff0000' : '#ff0000', isSelected ? 5 : 4, false);
    }

    if (zone.polyPoints.length > 0) {
      ctx.strokeStyle = isSelected ? '#ff0000' : color;
      ctx.lineWidth = isSelected ? 3 : 2;

      for (let i = 0; i < zone.polyPoints.length - 1; i++) {
        drawLine(ctx, zone.polyPoints[i].x, zone.polyPoints[i].y, 
                zone.polyPoints[i+1].x, zone.polyPoints[i+1].y, 
                isSelected ? '#ff0000' : color, isSelected ? 3 : 2);
      }

      if (zone.polyPoints.length === 4) {
        drawLine(ctx, zone.polyPoints[3].x, zone.polyPoints[3].y, 
                zone.polyPoints[0].x, zone.polyPoints[0].y, 
                isSelected ? '#ff0000' : color, isSelected ? 3 : 2);

        ctx.fillStyle = isSelected ? 'rgba(255, 0, 0, 0.1)' : 'rgba(255, 68, 68, 0.1)';
        ctx.beginPath();
        ctx.moveTo(zone.polyPoints[0].x, zone.polyPoints[0].y);
        ctx.lineTo(zone.polyPoints[1].x, zone.polyPoints[1].y);
        ctx.lineTo(zone.polyPoints[2].x, zone.polyPoints[2].y);
        ctx.lineTo(zone.polyPoints[3].x, zone.polyPoints[3].y);
        ctx.closePath();
        ctx.fill();
      }

      zone.polyPoints.forEach((point, index) => {
        drawPoint(ctx, point.x, point.y, index + 1, isSelected ? '#ff0000' : color);
      });
    }

    // Vẽ tên zone
    if (zone.name && zone.polyPoints.length > 0) {
      const centerX = zone.polyPoints.reduce((sum, p) => sum + p.x, 0) / zone.polyPoints.length;
      const centerY = zone.polyPoints.reduce((sum, p) => sum + p.y, 0) / zone.polyPoints.length;

      ctx.font = 'bold 16px Arial';
      ctx.fillStyle = isSelected ? '#ff0000' : '#000000';
      ctx.fillText(zone.name, centerX - 30, centerY - 20);
    }
  };

  // Vẽ lại tất cả
  const redrawAll = () => {
    if (!canvasRef.current) return;

    const ctx = canvasRef.current.getContext('2d');

    if (cameraData.imagePreview) {
      const img = new Image();
      img.src = cameraData.imagePreview;
      ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);
    }

    zones.forEach((zone, index) => {
      drawZone(ctx, zone, index === selectedZoneIndex);
    });

    if (currentZone.lines.length > 0 || currentZone.polyPoints.length > 0) {
      drawZone(ctx, currentZone, true);
    }
  };

  const handleSaveAll = () => {
    const output = generateOutput();
    onSave(output.list_camera[0].config);
  };

  const handleReset = () => {
    setZones([]);
    setCurrentZone({
      name: '',
      type: 1,
      lines: [],
      polyPoints: []
    });
    setZoneName('');
    setZoneType(1);
    setCurrentStep(1);
    setDrawing(false);
    setSelectedZoneIndex(null);

    if (canvasRef.current && cameraData.imagePreview) {
      const ctx = canvasRef.current.getContext('2d');
      const img = new Image();
      img.src = cameraData.imagePreview;
      img.onload = () => {
        ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);
      };
    }
  };

  useEffect(() => {
    redrawAll();
  }, [zones, currentZone, selectedZoneIndex]);

  const output = generateOutput();
  const totalZones = zones.length;

  // Tính toán trạng thái các bước
  const axisCompleted = currentZone.lines.length >= 1;
  const coordCompleted = currentZone.lines.length >= 2;
  const polygonCompleted = currentZone.polyPoints.length >= 4;

  return (
    <div style={{ padding: '20px' }}>
      {/* Header với số lượng zones */}
      <div style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        marginBottom: '20px',
        padding: '10px',
        background: '#f8f9fa',
        borderRadius: '8px'
      }}>
        <h3 style={{ margin: 0 }}>✏️ Vẽ Zone</h3>
        <div style={{ background: '#007bff', color: 'white', padding: '5px 15px', borderRadius: '20px' }}>
          Tổng số zones: {totalZones}
        </div>
      </div>

      {/* Nhập tên zone và chọn loại staff */}
      <div style={{ 
        marginBottom: '20px',
        padding: '15px',
        background: '#f8f9fa',
        borderRadius: '8px'
      }}>
        <div style={{ marginBottom: '15px' }}>
          <label style={{ display: 'block', marginBottom: '8px', fontWeight: 500 }}>
            Tên zone:
          </label>
          <input
            type="text"
            value={zoneName}
            onChange={(e) => setZoneName(e.target.value)}
            placeholder="Nhập tên cho zone (VD: Lối vào, Khu vực A, ...)"
            style={{
              width: '100%',
              padding: '12px',
              border: '2px solid #ddd',
              borderRadius: '8px',
              fontSize: '14px'
            }}
          />
        </div>

        <div>
          <label style={{ display: 'block', marginBottom: '8px', fontWeight: 500 }}>
            Chọn loại staff:
          </label>
          <div style={{ display: 'flex', gap: '10px' }}>
            {zoneTypes.map(type => (
              <button
                key={type.value}
                onClick={() => setZoneType(type.value)}
                style={{
                  flex: 1,
                  padding: '12px',
                  background: zoneType === type.value ? type.color : 'white',
                  color: zoneType === type.value ? 'white' : '#333',
                  border: `2px solid ${type.color}`,
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontSize: '14px',
                  fontWeight: 'bold',
                  transition: 'all 0.3s'
                }}
              >
                {type.label}
                {type.value === 3 && ' (8 điểm)'}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Steps với trạng thái */}
      <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
        <div style={{ 
          flex: 1, 
          padding: '15px', 
          background: currentStep === 1 ? '#e3f2fd' : '#f5f5f5',
          border: `2px solid ${axisCompleted ? '#28a745' : '#ddd'}`,
          borderRadius: '8px',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '20px', marginBottom: '5px' }}>1️⃣</div>
          <strong>Vẽ Axis</strong>
          <div style={{ 
            marginTop: '5px',
            color: axisCompleted ? '#28a745' : '#dc3545',
            fontWeight: 'bold'
          }}>
            {axisCompleted ? '✅' : '⏳'}
          </div>
        </div>

        <div style={{ 
          flex: 1, 
          padding: '15px', 
          background: currentStep === 2 ? '#e3f2fd' : '#f5f5f5',
          border: `2px solid ${coordCompleted ? '#28a745' : '#ddd'}`,
          borderRadius: '8px',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '20px', marginBottom: '5px' }}>2️⃣</div>
          <strong>Vẽ Coord</strong>
          <div style={{ 
            marginTop: '5px',
            color: coordCompleted ? '#28a745' : '#dc3545',
            fontWeight: 'bold'
          }}>
            {coordCompleted ? '✅' : '⏳'}
          </div>
        </div>

        <div style={{ 
          flex: 1, 
          padding: '15px', 
          background: currentStep === 3 ? '#e3f2fd' : '#f5f5f5',
          border: `2px solid ${polygonCompleted ? '#28a745' : '#ddd'}`,
          borderRadius: '8px',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '20px', marginBottom: '5px' }}>3️⃣</div>
          <strong>Vẽ Polygon</strong>
          <div style={{ 
            marginTop: '5px',
            color: polygonCompleted ? '#28a745' : '#dc3545',
            fontWeight: 'bold'
          }}>
            {currentZone.polyPoints.length}/4
          </div>
        </div>
      </div>

      {/* Canvas */}
      <div style={{ marginBottom: '20px' }}>
        <canvas
          ref={canvasRef}
          width={FIXED_WIDTH}
          height={FIXED_HEIGHT}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={() => setDrawing(false)}
          style={{
            width: '100%',
            height: 'auto',
            cursor: currentStep === 3 && currentZone.polyPoints.length < 4 ? 'crosshair' : 'default',
            border: '2px solid #ddd',
            borderRadius: '8px',
            background: '#f0f0f0'
          }}
        />
      </div>

      {/* Danh sách zones đã vẽ */}
      {zones.length > 0 && (
        <div style={{ 
          marginBottom: '20px',
          padding: '15px',
          background: '#f8f9fa',
          borderRadius: '8px'
        }}>
          <h4 style={{ margin: '0 0 10px 0' }}>📋 Các zone đã vẽ:</h4>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {zones.map((zone, index) => (
              <div
                key={index}
                style={{
                  padding: '15px',
                  background: selectedZoneIndex === index ? '#e3f2fd' : 'white',
                  border: `2px solid ${selectedZoneIndex === index ? '#007bff' : '#ddd'}`,
                  borderRadius: '8px',
                }}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                    <span style={{ fontWeight: 'bold' }}>{zone.name}</span>
                    <span style={{
                      padding: '4px 8px',
                      background: zoneTypes.find(t => t.value === zone.type)?.color,
                      color: 'white',
                      borderRadius: '4px',
                      fontSize: '12px'
                    }}>
                      {zoneTypes.find(t => t.value === zone.type)?.label}
                    </span>
                  </div>
                  <button
                    onClick={() => handleDeleteZone(index)}
                    style={{
                      background: 'none',
                      border: 'none',
                      color: '#dc3545',
                      cursor: 'pointer',
                      fontSize: '20px',
                      fontWeight: 'bold'
                    }}
                  >
                    ×
                  </button>
                </div>

                <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
                  {zoneTypes.map(type => (
                    <button
                      key={type.value}
                      onClick={() => handleUpdateZoneType(index, type.value)}
                      style={{
                        flex: 1,
                        padding: '8px',
                        background: zone.type === type.value ? type.color : 'white',
                        color: zone.type === type.value ? 'white' : '#333',
                        border: `1px solid ${type.color}`,
                        borderRadius: '4px',
                        cursor: 'pointer',
                        fontSize: '12px'
                      }}
                    >
                      {type.label}
                    </button>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Nút hoàn thành zone */}
      <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
        <button 
          onClick={handleCompleteZone}
          style={{
            width: '100%',
            padding: '15px',
            background: axisCompleted && coordCompleted && polygonCompleted && zoneName ? '#28a745' : '#6c757d',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            fontSize: '16px',
            fontWeight: 'bold',
            cursor: axisCompleted && coordCompleted && polygonCompleted && zoneName ? 'pointer' : 'not-allowed'
          }}
          disabled={!(axisCompleted && coordCompleted && polygonCompleted && zoneName)}
        >
          ✅ Hoàn thành zone
        </button>
      </div>

      {/* Preview luôn hiển thị */}
      <div style={{ 
        background: '#1e1e1e', 
        color: 'white', 
        padding: '15px', 
        borderRadius: '8px', 
        marginBottom: '20px' 
      }}>
        <h4 style={{ margin: '0 0 10px 0' }}>📋 Kết quả JSON ({totalZones} zones):</h4>

        <pre style={{ 
          background: '#2d2d2d', 
          padding: '10px', 
          borderRadius: '4px',
          overflow: 'auto',
          fontSize: '12px',
          maxHeight: '300px'
        }}>
          {JSON.stringify(output, null, 2)}
        </pre>

        <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
          <button 
            onClick={() => {
              navigator.clipboard.writeText(JSON.stringify(output, null, 2));
              alert('Đã copy JSON!');
            }}
            style={{
              flex: 1,
              padding: '10px',
              background: '#007bff',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer'
            }}
          >
            📋 Copy JSON
          </button>
        </div>

        {/* Hiển thị chi tiết coord cho từng zone */}
        {zones.length > 0 && (
          <div style={{ marginTop: '20px' }}>
            <h5 style={{ color: '#ffc107', marginBottom: '10px' }}>Chi tiết coord:</h5>
            {output.list_camera[0].config.zone.map((zone, index) => (
              <div key={index} style={{
                padding: '10px',
                background: '#2d2d2d',
                borderRadius: '4px',
                marginBottom: '10px'
              }}>
                <div style={{ color: zoneTypes.find(t => t.value === zone.type)?.color }}>
                  Zone {index + 1} - {zoneTypes.find(t => t.value === zone.type)?.label}
                </div>
                <div style={{ fontSize: '11px', color: '#aaa', marginTop: '5px' }}>
                  <strong>Axis:</strong> [{zone.axis.join(', ')}]
                </div>
                <div style={{ fontSize: '11px', color: '#aaa', marginTop: '5px' }}>
                  <strong>Coord ({zone.coord.length} điểm):</strong> [{zone.coord.join(', ')}]
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div style={{ display: 'flex', gap: '10px' }}>
        <button 
          onClick={handleReset}
          style={{
            flex: 1,
            padding: '10px',
            background: '#ffc107',
            color: '#212529',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
          }}
        >
          ⟲ Vẽ lại tất cả
        </button>
        <button 
          onClick={handleSaveAll}
          style={{
            flex: 1,
            padding: '10px',
            background: '#28a745',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
          }}
        >
          💾 Lưu tất cả ({totalZones} zones)
        </button>
      </div>
    </div>
  );
}

export default DrawingCanvas;
